7 Fonctions Utilisateur (User-Defined Functions)
# Definition
calculer_ratio &lt;- function(actifs, passifs) {
  if (any(is.na(actifs)) | any(is.na(passifs))) {
    warning("Valeurs manquantes detectees.")
  }
  ratio &lt;- actifs / passifs
  return(ratio)
}

# Application
entreprise_df$ratio_solv &lt;- calculer_ratio(entreprise_df$actifs_fixes,
                                            entreprise_df$passifs)
str(entreprise_df)
